class Solution {
public:
    bool canPartitionKSubsets(vector<int>& nums, int k) {
        int sum = 0;
        for (int num : nums) sum += num;
        if (sum % k != 0) return false;
        int target = sum / k;
        vector<bool> visited(nums.size(), false);
        vector<int> subsetSums(k, 0);
        return dfs(nums, k, target, subsetSums, visited, 0);
    }

    bool dfs(vector<int>& nums, int k, int target, vector<int>& subsetSums, vector<bool>& visited, int index) {
        if (k == 0) return true;
        if (index == nums.size()) return false;
        for (int i = 0; i < k; i++) {
            if (subsetSums[i] + nums[index] <= target && !visited[index]) {
                subsetSums[i] += nums[index];
                visited[index] = true;
                if (dfs(nums, k - (subsetSums[i] == target), target, subsetSums, visited, index + 1)) return true;
                subsetSums[i] -= nums[index];
                visited[index] = false;
            }
        }
        return false;
    }
};

